graphql.query:
query ($characterId: Int!, $episodeId: Int!) {
  character(characterId: $characterId) {
    id
    name
    gender
    status
  }

  location(locationId: 8) {
    id
    name
    dimension
  }
}

mutation
{
  createLocation(location: {name: "Aus", type: "Southzone", dimension: "123"})
  {
    id 
  }
  
  createCharacter(character: {name:"Nishant", type: "Ideal", status:"immortal", species:"fantasy", gender:"male", image:"png",originId:29413 , locationId:29413})
  {
    id
  }
  
  createEpisode(episode:{name: "Pilot" , air_date: "07/23/1998", episode:"1"} )
  {
    id
  }
  deleteLocations(locationIds: [29415, 29414] )
  {
    locationsDeleted
  }
}
